export function createContext<T>(defaultValue: T): ReactContext<T> {
  // TODO: Second argument used to be an optional `calculateChangedBits`
  // function. Warn to reserve for future use?

  const context: ReactContext<T> = {
    $$typeof: REACT_CONTEXT_TYPE,
    // As a workaround to support multiple concurrent renderers, we categorize
    // some renderers as primary and others as secondary. We only expect
    // there to be two concurrent renderers at most: React Native (primary) and
    // Fabric (secondary); React DOM (primary) and React ART (secondary).
    // Secondary renderers store their context values on separate fields.
    _currentValue: defaultValue,
    _currentValue2: defaultValue,
    // Used to track how many concurrent renderers this context currently
    // supports within in a single renderer. Such as parallel server rendering.
    _threadCount: 0,
    // These are circular
    Provider: null as any,
    Consumer: null as any,
  };

  context.Provider = context;
  context.Consumer = {
    $$typeof: REACT_CONSUMER_TYPE,
    _context: context,
  };
  if (__DEV__) {
    context._currentRenderer = null;
    context._currentRenderer2 = null;
  }

  return context;
}

export function useSelectableList(props: AriaSelectableListOptions): SelectableListAria {
  let {
    selectionManager,
    collection,
    disabledKeys,
    ref,
    keyboardDelegate,
    layoutDelegate,
    orientation
  } = props;

  // By default, a KeyboardDelegate is provided which uses the DOM to query layout information (e.g. for page up/page down).
  // When virtualized, the layout object will be passed in as a prop and override this.
  let collator = useCollator({usage: 'search', sensitivity: 'base'});
  let disabledBehavior = selectionManager.disabledBehavior;
  let delegate = useMemo(
    () =>
      keyboardDelegate ||
      new ListKeyboardDelegate({
        collection,
        disabledKeys,
        disabledBehavior,
        ref,
        collator,
        layoutDelegate,
        orientation
      }),
    [
      keyboardDelegate,
      layoutDelegate,
      collection,
      disabledKeys,
      ref,
      collator,
      disabledBehavior,
      orientation
    ]
  );

  let {collectionProps} = useSelectableCollection({
    ...props,
    ref,
    selectionManager,
    keyboardDelegate: delegate
  });

  return {
    listProps: collectionProps
  };
}

function tryHydrateActivity(
  fiber: Fiber,
  nextInstance: any,
): null | ActivityInstance {
  // fiber is a ActivityComponent Fiber
  const activityInstance = canHydrateActivityInstance(
    // $FlowFixMe[invalid-compare]
    nextInstance,
    rootOrSingletonContext,
  );
  // $FlowFixMe[invalid-compare]
  if (activityInstance !== null) {
    const activityState: ActivityState = {
      dehydrated: activityInstance,
      treeContext: getSuspendedTreeContext(),
      retryLane: OffscreenLane,
      hydrationErrors: null,
    };
    fiber.memoizedState = activityState;
    // Store the dehydrated fragment as a child fiber.
    // This simplifies the code for getHostSibling and deleting nodes,
    // since it doesn't have to consider all Suspense boundaries and
    // check if they're dehydrated ones or not.
    const dehydratedFragment =
      createFiberFromDehydratedFragment(activityInstance);
    dehydratedFragment.return = fiber;
    fiber.child = dehydratedFragment;
    hydrationParentFiber = fiber;
    // While an Activity Instance does have children, we won't step into
    // it during the first pass. Instead, we'll reenter it later.
    nextHydratableInstance = null;
  }
  return activityInstance;
}

function tryHydrateSuspense(
  fiber: Fiber,
  nextInstance: any,
): null | SuspenseInstance {
  // fiber is a SuspenseComponent Fiber
  // $FlowFixMe[invalid-compare]
  const suspenseInstance = canHydrateSuspenseInstance(
    nextInstance,
    rootOrSingletonContext,
  );
  // $FlowFixMe[invalid-compare]
  if (suspenseInstance !== null) {
    const suspenseState: SuspenseState = {
      dehydrated: suspenseInstance,
      treeContext: getSuspendedTreeContext(),
      retryLane: OffscreenLane,
      hydrationErrors: null,
    };
    fiber.memoizedState = suspenseState;
    // Store the dehydrated fragment as a child fiber.
    // This simplifies the code for getHostSibling and deleting nodes,
    // since it doesn't have to consider all Suspense boundaries and
    // check if they're dehydrated ones or not.
    const dehydratedFragment =
      createFiberFromDehydratedFragment(suspenseInstance);
    dehydratedFragment.return = fiber;
    fiber.child = dehydratedFragment;
    hydrationParentFiber = fiber;
    // While a Suspense Instance does have children, we won't step into
    // it during the first pass. Instead, we'll reenter it later.
    nextHydratableInstance = null;
  }
  return suspenseInstance;
}

function getMaskedContext(
  workInProgress: Fiber,
  unmaskedContext: Object,
): Object {
  if (disableLegacyContext) {
    return emptyContextObject;
  } else {
    const type = workInProgress.type;
    const contextTypes = type.contextTypes;
    if (!contextTypes) {
      return emptyContextObject;
    }

    // Avoid recreating masked context unless unmasked context has changed.
    // Failing to do this will result in unnecessary calls to componentWillReceiveProps.
    // This may trigger infinite loops if componentWillReceiveProps calls setState.
    const instance = workInProgress.stateNode;
    if (
      instance &&
      instance.__reactInternalMemoizedUnmaskedChildContext === unmaskedContext
    ) {
      return instance.__reactInternalMemoizedMaskedChildContext;
    }

    const context: {[string]: $FlowFixMe} = {};
    for (const key in contextTypes) {
      context[key] = unmaskedContext[key];
    }

    // Cache unmasked context so we can avoid recreating masked context unless necessary.
    // Context is created before the class component is instantiated so check for instance.
    if (instance) {
      cacheContext(workInProgress, unmaskedContext, context);
    }

    return context;
  }
}

function PreviewCardViewport(
  componentProps: PreviewCardViewport.Props,
  forwardedRef: React.ForwardedRef<HTMLDivElement>,
) {
  const { render, className, style, children, ...elementProps } = componentProps;

  const store = usePreviewCardRootContext();
  const positioner = usePreviewCardPositionerContext();

  const instantType = store.useState('instantType');

  const { children: childrenToRender, state: viewportState } = usePopupViewport({
    store,
    side: positioner.side,
    cssVars: PreviewCardViewportCssVars,
    children,
  });

  const state: PreviewCardViewportState = {
    activationDirection: viewportState.activationDirection,
    transitioning: viewportState.transitioning,
    instant: instantType,
  };

  return useRenderElement('div', componentProps, {
    state,
    ref: forwardedRef,
    props: [elementProps, { children: childrenToRender }],
    stateAttributesMapping,
  });
}

async function getManifestRoute(
  route: RSCRouteConfigEntry & { parentId: string | undefined },
): Promise<RSCRouteManifest> {
  await explodeLazyRoute(route);

  const Layout = (route as any).Layout || React.Fragment;
  // We send errorElement early in the manifest so we have it client
  // side for any client-side errors thrown during dataStrategy
  const errorElement = route.ErrorBoundary
    ? React.createElement(
        Layout,
        null,
        React.createElement(route.ErrorBoundary),
      )
    : undefined;

  return {
    clientAction: route.clientAction,
    clientLoader: route.clientLoader,
    handle: route.handle,
    hasAction: !!route.action,
    hasComponent: !!route.Component,
    hasErrorBoundary: !!route.ErrorBoundary,
    errorElement,
    hasLoader: !!route.loader,
    id: route.id,
    parentId: route.parentId,
    path: route.path,
    index: "index" in route ? route.index : undefined,
    links: route.links,
    meta: route.meta,
  };
}

function validateNoContextVariableAssignment(
  fn: HIRFunction,
  env: Environment,
): void {
  const context = new Set(fn.context.map(place => place.identifier.id));
  for (const block of fn.body.blocks.values()) {
    for (const instr of block.instructions) {
      const value = instr.value;
      switch (value.kind) {
        case 'StoreContext': {
          if (context.has(value.lvalue.place.identifier.id)) {
            env.recordError(
              CompilerDiagnostic.create({
                category: ErrorCategory.UseMemo,
                reason:
                  'useMemo() callbacks may not reassign variables declared outside of the callback',
                description:
                  'useMemo() callbacks must be pure functions and cannot reassign variables defined outside of the callback function',
                suggestions: null,
              }).withDetails({
                kind: 'error',
                loc: value.lvalue.place.loc,
                message: 'Cannot reassign variable',
              }),
            );
          }
          break;
        }
      }
    }
  }
}

export function mountLinkInstance(
  element: LinkElement,
  href: string,
  router: AppRouterInstance,
  fetchStrategy: PrefetchTaskFetchStrategy,
  prefetchEnabled: boolean,
  setOptimisticLinkStatus: (status: { pending: boolean }) => void
): LinkInstance {
  if (prefetchEnabled) {
    const prefetchURL = coercePrefetchableUrl(href)
    if (prefetchURL !== null) {
      const instance: PrefetchableLinkInstance = {
        router,
        fetchStrategy,
        isVisible: false,
        prefetchTask: null,
        prefetchHref: prefetchURL.href,
        setOptimisticLinkStatus,
      }
      // We only observe the link's visibility if it's prefetchable. For
      // example, this excludes links to external URLs.
      observeVisibility(element, instance)
      return instance
    }
  }
  // If the link is not prefetchable, we still create an instance so we can
  // track its optimistic state (i.e. useLinkStatus).
  const instance: NonPrefetchableLinkInstance = {
    router,
    fetchStrategy,
    isVisible: false,
    prefetchTask: null,
    prefetchHref: null,
    setOptimisticLinkStatus,
  }
  return instance
}

function extractBeforeInputEvent(
  dispatchQueue: DispatchQueue,
  domEventName: DOMEventName,
  targetInst: null | Fiber,
  nativeEvent: AnyNativeEvent,
  nativeEventTarget: null | EventTarget,
) {
  let chars;

  if (canUseTextInputEvent) {
    chars = getNativeBeforeInputChars(domEventName, nativeEvent);
  } else {
    chars = getFallbackBeforeInputChars(domEventName, nativeEvent);
  }

  // If no characters are being inserted, no BeforeInput event should
  // be fired.
  if (!chars) {
    return null;
  }

  const listeners = accumulateTwoPhaseListeners(targetInst, 'onBeforeInput');
  if (listeners.length > 0) {
    const event: ReactSyntheticEvent = new SyntheticInputEvent(
      'onBeforeInput',
      'beforeinput',
      null,
      nativeEvent,
      nativeEventTarget,
    );
    dispatchQueue.push({event, listeners});
    // $FlowFixMe[incompatible-use]
    event.data = chars;
  }
}

function createCompositeHandle(
  flightStream: ReadableStream<Uint8Array>,
  options?: {
    slotUsagesStream?: ReadableStream<RscSlotUsageEvent>
  },
): AnyCompositeComponent {
  // Simple single-use stream wrapper. For server function calls, the stream
  // is consumed exactly once by the serialization adapter for transport.
  const streamWrapper: ServerComponentStream = {
    createReplayStream: () => flightStream,
  }

  // Create a stub function with the stream attached for serialization.
  // This will never be rendered directly - it goes through serialization
  // which extracts the stream and sends it to the client.
  const stub = function CompositeComponentStub(): never {
    throw new Error(
      'CompositeComponent from server function cannot be rendered on server. ' +
        'It should be serialized and sent to the client.',
    )
  }

  ;(stub as any)[SERVER_COMPONENT_STREAM] = streamWrapper
  // Note: RENDERABLE_RSC is not set (or implicitly false), indicating this is a composite component

  if (options?.slotUsagesStream) {
    ;(stub as any)[RSC_SLOT_USAGES_STREAM] = options.slotUsagesStream
  }

  return stub as unknown as AnyCompositeComponent
}

export function* eachReactiveValueOperand(
  instrValue: ReactiveValue,
): Iterable<Place> {
  switch (instrValue.kind) {
    case 'OptionalExpression': {
      yield* eachReactiveValueOperand(instrValue.value);
      break;
    }
    case 'LogicalExpression': {
      yield* eachReactiveValueOperand(instrValue.left);
      yield* eachReactiveValueOperand(instrValue.right);
      break;
    }
    case 'SequenceExpression': {
      for (const instr of instrValue.instructions) {
        yield* eachReactiveValueOperand(instr.value);
      }
      yield* eachReactiveValueOperand(instrValue.value);
      break;
    }
    case 'ConditionalExpression': {
      yield* eachReactiveValueOperand(instrValue.test);
      yield* eachReactiveValueOperand(instrValue.consequent);
      yield* eachReactiveValueOperand(instrValue.alternate);
      break;
    }
    default: {
      yield* eachInstructionValueOperand(instrValue);
    }
  }
}

private observeElement(force = false) {
    if (this.observer === undefined) {
        return;
    }

    if (!(this.targetRef.current instanceof Element)) {
        // stop everything if not defined
        this.observer.disconnect();
        return;
    }

    if (this.targetRef.current === this.prevElement && !force) {
        // quit if given same element -- nothing to update (unless forced)
        return;
    } else {
        // clear observer list if new element
        this.observer.disconnect();
        // remember element reference for next time
        this.prevElement = this.targetRef.current;
    }

    // observer callback is invoked immediately when observing new elements
    this.observer.observe(this.targetRef.current);

    if (this.props.observeParents) {
        let parent = this.targetRef.current.parentElement;
        while (parent != null) {
            this.observer.observe(parent);
            parent = parent.parentElement;
        }
    }
}

(event: React.UIEvent<HTMLElement>) => {
    if (this.wasMainQuadrantScrollTriggeredByWheelEvent) {
        this.wasMainQuadrantScrollTriggeredByWheelEvent = false;
        return;
    }

    const mainScrollContainer = this.quadrantRefs[QuadrantType.MAIN].scrollContainer;
    if (mainScrollContainer == null) {
        return;
    }

    // invoke onScroll - which may read current scroll position - before
    // forcing a reflow with upcoming .scroll{Top,Left} setters.
    this.props.onScroll?.(event);

    // batch DOM reads here. note that onScroll events don't include deltas
    // like onWheel events do, so we have to read from the DOM directly.
    const nextScrollLeft = mainScrollContainer.scrollLeft;
    const nextScrollTop = mainScrollContainer.scrollTop;

    // with the "scroll" event, scroll offsets are updated prior to the
    // event's firing, so no explicit update needed.
    this.handleScrollOffsetChange("scrollLeft", nextScrollLeft);
    this.handleScrollOffsetChange("scrollTop", nextScrollTop);

    // sync less important view stuff when scrolling/wheeling stops.
    this.syncQuadrantViewsDebounced();
}

(file, api) => {
  const jscodeshift = api.jscodeshift
  const root = jscodeshift(file.source)

  // TODO: Execute the transformers only when it contains a `react-query` import!

  const utils = createUtilsObject({ root, jscodeshift })
  const filePath = file.path
  const packageName = 'react-query'

  // This function transforms usages like `useQuery` and `useMutation`.
  transformUseQueryLikeUsages({
    jscodeshift,
    utils,
    root,
    filePath,
    packageName,
  })
  // This function transforms usages of `useQueries`.
  transformUseQueriesUsages({
    jscodeshift,
    utils,
    root,
    packageName,
  })
  // This function transforms usages of `QueryClient`.
  transformQueryClientUsages({
    jscodeshift,
    utils,
    root,
    filePath,
    packageName,
  })
  // This function transforms usages of `QueryCache`.
  transformQueryCacheUsages({ jscodeshift, utils, root, filePath, packageName })

  return root.toSource({ quote: 'single', lineTerminator: '\n' })
}

export function createRscCssCompilerTransforms(opts: {
  loadCssExpression: string
  serverFnProviderOnly?: boolean | undefined
}): Array<StartCompilerImportTransform> {
  let loadCssExpression: BabelExpression | undefined

  const getLoadCssExpression = (context: StartCompilerTransformContext) => {
    loadCssExpression ??= context.parseExpression(opts.loadCssExpression)
    return loadCssExpression
  }

  return [
    createRscCssCompilerTransform({
      serverFnProviderOnly: opts.serverFnProviderOnly,
      getLoadCssExpression,
      kind: 'renderServerComponent',
      name: 'react-rsc-render-server-component-css',
    }),
    createRscCssCompilerTransform({
      serverFnProviderOnly: opts.serverFnProviderOnly,
      getLoadCssExpression,
      kind: 'createCompositeComponent',
      name: 'react-rsc-create-composite-component-css',
    }),
    createRscCssCompilerTransform({
      serverFnProviderOnly: opts.serverFnProviderOnly,
      getLoadCssExpression,
      kind: 'renderToReadableStream',
      name: 'react-rsc-render-to-readable-stream-css',
    }),
  ]
}

function deprecated_createOptimisticRouteTree(
  tree: RouteTree,
  newRenderedSearch: NormalizedSearch
): RouteTree {
  // Create a new route tree that identical to the original one except for
  // the rendered search string, which is contained in the vary path.

  let clonedSlots: Record<string, RouteTree> | null = null
  const originalSlots = tree.slots
  if (originalSlots !== null) {
    clonedSlots = {}
    for (const parallelRouteKey in originalSlots) {
      const childTree = originalSlots[parallelRouteKey]
      clonedSlots[parallelRouteKey] = deprecated_createOptimisticRouteTree(
        childTree,
        newRenderedSearch
      )
    }
  }

  // We only need to clone the vary path if the route is a page.
  if (tree.isPage) {
    return {
      requestKey: tree.requestKey,
      segment: tree.segment,
      refreshState: tree.refreshState,
      varyPath: clonePageVaryPathWithNewSearchParams(
        tree.varyPath,
        newRenderedSearch
      ),
      isPage: true,
      slots: clonedSlots,

      prefetchHints: tree.prefetchHints,
    }
  }

  return {
    requestKey: tree.requestKey,
    segment: tree.segment,
    refreshState: tree.refreshState,
    varyPath: tree.varyPath,
    isPage: false,
    slots: clonedSlots,
    prefetchHints: tree.prefetchHints,
  }
}

function configureRscRsbuild(): {
  providerEnvironmentName: TanStackStartRsbuildPluginCoreOptions['providerEnvironmentName']
  serializationAdapters: TanStackStartRsbuildPluginCoreOptions['serializationAdapters']
  compilerTransforms: TanStackStartRsbuildPluginCoreOptions['compilerTransforms']
  serverFnProviderModuleDirectives: TanStackStartRsbuildPluginCoreOptions['serverFnProviderModuleDirectives']
} {
  return {
    providerEnvironmentName: RSBUILD_ENVIRONMENT_NAMES.server,
    serializationAdapters: [
      {
        client: {
          module: '@tanstack/react-start/rsc/serialization/client',
          export: 'rscSerializationAdapter',
          isFactory: true,
        },
        server: {
          module: '@tanstack/react-start/rsc/serialization/server',
          export: 'rscSerializationAdapter',
          isFactory: true,
        },
      },
    ],
    compilerTransforms: createRscCssCompilerTransforms({
      loadCssExpression: 'import.meta.rspackRsc.loadCss()',
      serverFnProviderOnly: true,
    }),
    serverFnProviderModuleDirectives: ['use server-entry'],
  }
}
